vector<string> split(const string& str, char delimiter) {
  vector<string> words;
  size_t pos = 0;
  while (true) {
    size_t pos = str.find(delimiter, pos);
    if (pos == string::npos) {
      words.push_back(str.substr(pos));
      break;
    }
    words.push_back(str.substr(pos, pos - pos));
    pos = pos + 1;
  }
  return words;
