class Queue:
    def __init__(self):
        self.stack1 = Stack()
        self.stack2 = Stack()

    def push(self, item):
        self.stack1.push(item)

    def pop(self):
        if not self.stack1.is_empty():
            item = self.stack1.pop()
            self.stack2.push(item)
        else:
            raise ValueError("Queue is empty")

    def peek(self):
        if self.stack1.is_empty():
            raise ValueError("Queue is empty")
        return self.stack1.peek()

    def is_empty(self):
        return self.stack1.is_empty() or self.stack2.is_empty()

class Stack:
    def __init__(self):
        self.items = []

    def push(self, item):
        self.items.append(item)

    def pop(self):
        if self.is_empty():
            raise ValueError("Stack is empty")
        return self.items.pop()

    def peek(self):
        if self.is_empty():
            raise ValueError("Stack is empty")
        return self.items[-1]

    def is_empty(self):
        return len(self.items) == 0
